//! Auto-generated by the spec-word-compliance workflow.
//!
//! Area: "Cell merging: vMerge (vertical) and gridSpan (horizontal) with
//! merge-revision accept/reject".
//!
//! Each `#[test]` encodes a behavioural constraint from ISO 29500-1 / ECMA-376
//! Annex A / MS-OI29500 about how Word consumes and how a conformant serializer
//! emits table-cell merge markup. A FAILING assertion here is NOT a flaky test:
//! it encodes a real Word-compliance gap in the stemma engine, and the fix is
//! to make stemma match Word, never to weaken the assertion.
//!
//! Methodology guard (consumption vs. save):
//!  - xmlContains/xmlOmits/xmlRegex are asserted on `reserialize()` and are
//!    valid only for markup stemma's serializer ACTIVELY generates/restructures
//!    (Annex A child ordering, structural synthesis, opens-clean validity).
//!    stemma round-trips untouched content byte-verbatim, so an xml assertion on
//!    a verbatim-preserved attribute would be a test-bug, not a gap.
//!  - Word CONSUMPTION semantics ("continue joins the merge", "0 == 1",
//!    "ignored revision") are asserted on the READ side
//!    (read_accepted()/read_rejected().to_text()).

use stemma::ExportOptions;
use stemma::api::{Document, validate};

// ─── Prelude: minimal-.docx plumbing (mirrors the shared spec-suite prelude) ─

/// Build a valid minimal `.docx`. `body_xml` is wrapped in
/// `<w:document …><w:body>…</w:body></w:document>`. `extra_parts` is a list of
/// `(part_path, xml)` placed under `word/` (e.g. `("styles.xml", "<w:styles…>")`);
/// each gets a Content_Types override and a document.xml.rels relationship.
fn make_docx(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:body>{body_xml}</w:body></w:document>"#
    );

    // Content-type override per extra part.
    let mut overrides = String::from(
        r#"<Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>"#,
    );
    let mut doc_rel_entries = String::new();
    for (i, (part, _xml)) in extra_parts.iter().enumerate() {
        let ct = match *part {
            "styles.xml" => {
                "application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"
            }
            "numbering.xml" => {
                "application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml"
            }
            other => panic!("make_docx: no content-type mapping for extra part {other}"),
        };
        overrides.push_str(&format!(
            r#"<Override PartName="/word/{part}" ContentType="{ct}"/>"#
        ));
        let rel_type = match *part {
            "styles.xml" => {
                "http://schemas.openxmlformats.org/officeDocument/2006/relationships/styles"
            }
            "numbering.xml" => {
                "http://schemas.openxmlformats.org/officeDocument/2006/relationships/numbering"
            }
            other => panic!("make_docx: no rel-type mapping for extra part {other}"),
        };
        doc_rel_entries.push_str(&format!(
            r#"<Relationship Id="rIdX{i}" Type="{rel_type}" Target="{part}"/>"#
        ));
    }

    let content_types = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/>{overrides}</Types>"#
    );
    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#;
    let doc_rels = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">{doc_rel_entries}</Relationships>"#
    );

    use std::io::Write;
    use zip::write::FileOptions;
    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(std::io::Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (part, xml) in extra_parts {
            zip.start_file(format!("word/{part}"), opts).unwrap();
            zip.write_all(xml.as_bytes()).unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

/// Unzip a `.docx` and return `word/document.xml` as a String.
fn document_xml_of(docx: &[u8]) -> String {
    let mut zip = zip::ZipArchive::new(std::io::Cursor::new(docx)).expect("open docx zip");
    let mut file = zip
        .by_name("word/document.xml")
        .expect("word/document.xml present");
    use std::io::Read;
    let mut s = String::new();
    file.read_to_string(&mut s).expect("read document.xml");
    s
}

/// Parse + re-serialize, returning the resulting `word/document.xml`. This is
/// the engine's serializer output (for ordering/synthesis assertions), NOT a
/// statement about Word's save-time normalization of verbatim content.
fn reserialize(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse");
    let out = doc.serialize(&ExportOptions::default()).expect("serialize");
    document_xml_of(&out)
}

/// opens-clean helper: stemma's package/wordprocessing/schema validator reports
/// no errors.
fn assert_opens_clean(bytes: &[u8], rule: &str) {
    let report = validate(bytes);
    assert!(
        report.ok,
        "{rule} — expected opens-clean (no validator errors), got issues: {:?}",
        report.issues
    );
}

